public class Main {
    public static void main(String[] args) {
        // Autoboxing
        Integer num1 = 100;
        Integer num2 = 100;

        // Caching: same object for -128 to 127
        System.out.println("num1 == num2: " + (num1 == num2));  // true

        Integer num3 = 200;
        Integer num4 = 200;
        System.out.println("num3 == num4: " + (num3 == num4));  // false

        // Parsing
        int parsed = Integer.parseInt("456");
        double d = Double.parseDouble("3.14");
        System.out.println("Parsed int: " + parsed);

        // Char utilities
        System.out.println("Is digit '5': " + Character.isDigit('5'));
        System.out.println("Is letter 'A': " + Character.isLetter('A'));
    }
}
